---@class LFightServerReportGetter
local LFightServerReportGetter = LxClass("LFightServerReportGetter", nil)

local PJX = CardEHT
local PJXProtoMessage = PJX.ProtoMessage

LXImport(".LFightPbParser")
LFightServerReportGetter.REQUESTING = 1
LFightServerReportGetter.FINISH = 2

function LFightServerReportGetter:LFightServerReportGetter()
    self._state = -1
    self._retryCnt = 0
    self._retryMax = 1
    self._timeOut = 3
end
--[[
reportInfo = {
reportId,
reportUrl,
serverId,
}
]]


function LFightServerReportGetter:Start(reportInfo)

    self._key = reportInfo.key
    self._startTime = self:GetCurTime()

    self._reportId = reportInfo.reportId
    self._reportFullUrl = reportInfo.url
    self._callback = reportInfo.callback
    self._failCall = reportInfo.failCall
    self._combatType = reportInfo.combatType


    self:StartRequest()

end



function LFightServerReportGetter:StartRequest()
    self._isPbData = self:IsPbData()

    if self._state == LFightServerReportGetter.FINISH then
        if self._callback then
            self._callback(self._reportTable)
        end
        return
    elseif self._state == LFightServerReportGetter.REQUESTING then
        return
    end
    self:RequestWebReport()
end

function LFightServerReportGetter:IsPbData()
    local s,e = string.find(self._reportFullUrl,"pb")
    if s and e then
        return true
    end
    return false
end

function LFightServerReportGetter:RequestWebReport()
    self._state = LFightServerReportGetter.REQUESTING

    self._reqTime = self:GetCurTime()
    local reportId = self._reportId

    if self._isPbData then
        local urlList = {self._reportFullUrl}
        self:PbWebRequest(urlList,reportId)
    end
end

function LFightServerReportGetter:PbWebRequest(urlList,reportId)
    LxHttpHelper.DoWebDownFile(urlList, function(url, ret, result, progress, bytes)
        if self:IsDestroy() then return end
        if (ret == CS.YXWebRet.ok) then
            local msgId = LProtoHelper.GetProtoId("CombatReportResp")
            local protoReader = PJXProtoMessage.New()
            protoReader:SetMessage(bytes)
            local str = protoReader:GetMessage()

            if self._frameParser then
                self._frameParser:Destroy()
            end

            self._frameParser= LFightPbParser:New()
            self._frameParser:ParsePb(msgId,str,function (reportTable)
                if self:IsDestroy() then return end
                --local reportTable = LProtoHelper.ConvertToProto(msgId,protoReader:ToLuaByteBuffer())
                if (CS.IsUnityEdit()) then
                    gLFightManager:SavePbReportToFile(reportId,bytes)
                    local tbl = LProtoHelper.ProtoToPureTable(reportTable)
                    local str = JSON.encode(tbl)
                    gLFightManager:SaveReportToFile(reportId.."tojson",str)
                end

                self._reportTable = reportTable
                self._state = LFightServerReportGetter.FINISH
                if self._callback then
                    self._callback(reportTable)
                end
            end)

            self:StopRetry()
        elseif ret == CS.YXWebRet.Error then
            GF.ShowMessage(ccClientText(10153))
            local combatType = self._combatType
            if combatType then
                gModelBattle:RecordVideoBattleLife(combatType,false)
            end

            self._isError = true

            if self._failCall then
                self._failCall()
            end

            --超时的过几s后重新请求一次
        elseif ret == CS.YXWebRet.Timeout then
            if self._retryCnt < self._retryMax then
                self:StartDelayRequest()
            else
                local combatType = self._combatType
                if combatType then
                    gModelBattle:RecordVideoBattleLife(combatType,false)
                end

                if self._failCall then
                    self._failCall()
                end
            end
        end
    end, true, 1)
end




function LFightServerReportGetter:StartDelayRequest()
    if not self._timer then
        self._timer = LxTimer:New()
    end
    self._retryCnt = self._retryCnt + 1
    local key = "delayRequest"
    local delayTime = 1
    self._timer:TimerRemoveByKey(key)
    self._timer:TimerCreate(key,function(...)
        self:RequestWebReport()
    end,delayTime,false,1)
end

function LFightServerReportGetter:StopRetry()
    if not self._timer then
        return
    end
    self._timer:TimerRemoveByKey("delayRequest")
end
-----------------------------------------------------------------
function LFightServerReportGetter:IsDestroy()
    return self._isDestroy
end

function LFightServerReportGetter:Destroy()

    if self._timer  then
        self._timer:Destroy()
        self._timer = nil
    end

    if self._frameParser then
        self._frameParser:Destroy()
    end

    table.removeall(self)
    self._isDestroy = true
end

function LFightServerReportGetter:CanReplace()
    if self._isDestroy then
        return true
    end

    if self._isError then
        return true
    end

    if self:CheckTimeOut() then
        return true
    end

    if self:IsFinish() then
        return true
    end


    return false
end

function LFightServerReportGetter:CheckTimeOut()
    if self._state == LFightServerReportGetter.REQUESTING then
        local time = self:GetCurTime()
        local timeOut = self._timeOut
        local reqTime = self._reqTime
        if time - reqTime > timeOut then
            return true
        end
    end
    return false
end

function LFightServerReportGetter:GetCurTime()
    return GetTimestamp()
end

function LFightServerReportGetter:IsFinish()
    return self._state == LFightServerReportGetter.FINISH
end


function LFightServerReportGetter:GetReportTable()
    return self._reportTable
end

---已缓存时间，超出可删除缓存
function LFightServerReportGetter:GetStartTime()
    return self._startTime or GetTimestamp()
end

function LFightServerReportGetter:GetKey()
    return self._key
end

return LFightServerReportGetter